/**
 * Setup the Shopify dev store as an apparel test harness for the In-Season
 * Shopify lane (sprint 2026-05-19). Replaces the default snowboard test data
 * with 25 REAL apparel products from the official Shopify Partners repo
 * (United By Blue · public CSV since 2014 · 104 variants total · 95 with SKU).
 *
 * Source: /tmp/apparel-plan.json (generated by parsing
 * https://raw.githubusercontent.com/shopifypartners/shopify-product-csvs-and-images/master/csv-files/apparel.csv)
 *
 * Operations:
 *  1. DELETE existing snowboard products (the 17 from "Start with test data")
 *  2. CREATE 25 apparel products via productSet (single-mutation w/variants)
 *
 * productSet 2026-01 fields used:
 *  - title, descriptionHtml, vendor, productType, tags, status (ACTIVE)
 *  - productOptions [{name, values [{name}]}]
 *  - variants [{sku, price, compareAtPrice, optionValues, inventoryItem.cost,
 *      inventoryQuantities [{locationId, name: "available", quantity}]}]
 *  - files [{originalSource, contentType: IMAGE}]
 *
 * COGS: synthesised at 45% of price (apparel canon).
 * Inventory: from CSV `Variant Inventory Qty` field, fallback 50 units.
 *
 * Usage:
 *   SHOPIFY_DEMO_SHOP=aimily-mlyel0nm.myshopify.com \
 *   SHOPIFY_DEMO_TOKEN=shpat_xxx \
 *   node scripts/setup-shopify-apparel-store.mjs
 *
 * Add --dry-run to print plan without executing.
 * Add --no-delete to skip snowboard deletion (idempotent re-run).
 */

import { readFileSync } from 'fs';

const SHOP = process.env.SHOPIFY_DEMO_SHOP;
const TOKEN = process.env.SHOPIFY_DEMO_TOKEN;
const API_VERSION = '2026-01';
const LOCATION_ID = 'gid://shopify/Location/89110315253'; // "My Custom Location" (Toronto)

const DRY_RUN = process.argv.includes('--dry-run');
const NO_DELETE = process.argv.includes('--no-delete');

if (!SHOP || !TOKEN) {
  console.error('SHOPIFY_DEMO_SHOP and SHOPIFY_DEMO_TOKEN env vars required');
  process.exit(1);
}

const GQL_URL = `https://${SHOP}/admin/api/${API_VERSION}/graphql.json`;

async function gql(query, variables) {
  const res = await fetch(GQL_URL, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'X-Shopify-Access-Token': TOKEN },
    body: JSON.stringify({ query, variables }),
  });
  const json = await res.json();
  if (json.errors) throw new Error(`GraphQL errors: ${JSON.stringify(json.errors)}`);
  return json.data;
}

async function listAllProducts() {
  const QUERY = /* GraphQL */ `
    query AllProducts($after: String) {
      products(first: 50, after: $after) {
        pageInfo { hasNextPage endCursor }
        edges { node { id title handle } }
      }
    }
  `;
  const out = [];
  let after = null;
  while (true) {
    const data = await gql(QUERY, { after });
    for (const e of data.products.edges) out.push(e.node);
    if (!data.products.pageInfo.hasNextPage) break;
    after = data.products.pageInfo.endCursor;
  }
  return out;
}

async function deleteProduct(id) {
  const MUT = /* GraphQL */ `
    mutation ProductDelete($input: ProductDeleteInput!) {
      productDelete(input: $input) {
        deletedProductId
        userErrors { field message }
      }
    }
  `;
  return gql(MUT, { input: { id } });
}

const PRODUCT_SET = /* GraphQL */ `
  mutation ProductSet($input: ProductSetInput!, $synchronous: Boolean!) {
    productSet(input: $input, synchronous: $synchronous) {
      product {
        id
        title
        handle
        variants(first: 30) {
          nodes { id sku price selectedOptions { name value } }
        }
      }
      userErrors { field message code }
    }
  }
`;

function planToProductSetInput(p) {
  // Take all non-empty option names verbatim (including "Title" for single-option products).
  // Shopify requires productOptions to be sent even when it's the Title default — see
  // PRODUCT_OPTIONS_INPUT_MISSING error encountered in first run.
  const optionNames = p.option_names.filter((n) => n);
  // Build OptionSetInput[]: collect unique values per name from variants in encounter order
  const productOptions = optionNames.map((name, idx) => {
    const seen = new Set();
    const ordered = [];
    for (const v of p.variants) {
      const val = v.option_values[idx];
      if (val && !seen.has(val)) {
        seen.add(val);
        ordered.push(val);
      }
    }
    return {
      name,
      position: idx + 1,
      values: ordered.map((name) => ({ name })),
    };
  });

  // Build variants — optionValues align by position with optionNames
  const variants = p.variants.map((v, idx) => {
    const optVals = optionNames.map((name, i) => ({
      optionName: name,
      name: v.option_values[i] || v.option_values[0] || 'Default Title',
    }));
    const cost = (parseFloat(v.price) * 0.45).toFixed(2);
    return {
      sku: v.sku,
      price: v.price,
      ...(v.compare_at_price ? { compareAtPrice: v.compare_at_price } : {}),
      ...(v.barcode ? { barcode: v.barcode } : {}),
      optionValues: optVals,
      inventoryItem: { cost, tracked: true },
      inventoryQuantities: [
        { locationId: LOCATION_ID, name: 'available', quantity: v.inventory_qty },
      ],
    };
  });

  // Files: just the master image (apparel.csv often has variant-specific images
  // but they're URLs only; setting one per variant requires file association which
  // ProductSetInput supports via variant.file. For simplicity ship the master.)
  const files = p.master_image
    ? [{ originalSource: p.master_image, contentType: 'IMAGE', alt: p.title }]
    : [];

  const input = {
    title: p.title,
    handle: p.handle,
    descriptionHtml: p.body_html,
    vendor: p.vendor || 'United By Blue',
    productType: p.product_type || 'Apparel',
    tags: p.tags,
    status: 'ACTIVE',
    productOptions,
    variants,
    ...(files.length > 0 ? { files } : {}),
  };
  return input;
}

async function createProduct(p) {
  const input = planToProductSetInput(p);
  const data = await gql(PRODUCT_SET, { input, synchronous: true });
  const errs = data.productSet.userErrors;
  if (errs.length > 0) {
    throw new Error(`productSet errors: ${JSON.stringify(errs)}`);
  }
  return data.productSet.product;
}

async function sleep(ms) {
  return new Promise((r) => setTimeout(r, ms));
}

async function main() {
  console.log(`Shop: ${SHOP}`);
  console.log(`API:  ${GQL_URL}`);
  console.log(`Location: ${LOCATION_ID}`);

  const plan = JSON.parse(readFileSync('/tmp/apparel-plan.json', 'utf-8'));
  console.log(`Plan: ${plan.length} products, ${plan.reduce((a, p) => a + p.variants.length, 0)} variants`);

  if (DRY_RUN) {
    console.log('\n=== DRY RUN — first 3 products planned ===');
    for (const p of plan.slice(0, 3)) {
      console.log(JSON.stringify(planToProductSetInput(p), null, 2));
    }
    return;
  }

  if (!NO_DELETE) {
    console.log('\n=== Phase 1: delete existing products ===');
    const existing = await listAllProducts();
    console.log(`Found ${existing.length} existing products to delete`);
    for (let i = 0; i < existing.length; i++) {
      const p = existing[i];
      try {
        const r = await deleteProduct(p.id);
        const errs = r.productDelete.userErrors;
        if (errs.length > 0) {
          console.log(`[${i + 1}/${existing.length}] DELETE FAIL ${p.handle}: ${JSON.stringify(errs)}`);
        } else {
          console.log(`[${i + 1}/${existing.length}] DELETE OK ${p.handle}`);
        }
      } catch (e) {
        console.log(`[${i + 1}/${existing.length}] DELETE FAIL ${p.handle}: ${e.message}`);
      }
      await sleep(300); // gentle pacing
    }
  } else {
    console.log('\n=== Phase 1: SKIPPED (--no-delete) ===');
  }

  console.log('\n=== Phase 2: create apparel products via productSet ===');
  let ok = 0;
  let fail = 0;
  const failures = [];
  for (let i = 0; i < plan.length; i++) {
    const p = plan[i];
    try {
      const result = await createProduct(p);
      ok++;
      console.log(
        `[${i + 1}/${plan.length}] OK ${p.handle} → ${result.id.split('/').pop()} (${result.variants.nodes.length} variants)`
      );
    } catch (e) {
      fail++;
      failures.push({ handle: p.handle, error: e.message.slice(0, 300) });
      console.log(`[${i + 1}/${plan.length}] FAIL ${p.handle}: ${e.message.slice(0, 200)}`);
    }
    await sleep(800); // gentle pacing
  }
  console.log(`\nPhase 2: ${ok} OK, ${fail} FAIL`);
  if (failures.length > 0) {
    console.log('\nFailures:\n' + JSON.stringify(failures, null, 2));
  }

  console.log('\n=== DONE ===');
}

main().catch((e) => {
  console.error('Fatal:', e);
  process.exit(1);
});
